import{_ as e,o as a,c as n,ai as i}from"./chunks/framework.DMjte4z8.js";const b=JSON.parse('{"title":"vJASS 进阶编程","description":"","frontmatter":{"title":"vJASS 进阶编程","category":"scripting","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/vjass-oop-lesson.128236/","https://www.bilibili.com/video/BV1e3xpzeEgZ/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=127853","https://vjass.wordpress.com/","https://github.com/zxcvbffg/Warcraft3-vJASS-","https://github.com/topics/vjass"]},"headers":[],"relativePath":"scripting/vjass-进阶编程.md","filePath":"scripting/vjass-进阶编程.md","lastUpdated":1778216780000}'),t={name:"scripting/vjass-进阶编程.md"};function r(l,s,o,p,c,d){return a(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="vjass-进阶编程" tabindex="-1">vJASS 进阶编程 <a class="header-anchor" href="#vjass-进阶编程" aria-label="Permalink to “vJASS 进阶编程”">​</a></h1><h2 id="vjass高级语法特性" tabindex="-1">vJASS高级语法特性 <a class="header-anchor" href="#vjass高级语法特性" aria-label="Permalink to “vJASS高级语法特性”">​</a></h2><p>本节将带你学习vJASS相对于普通JASS独有的三大高级特性：函数重载、接口与实现、作用域与命名空间。掌握这些知识后，你的代码将变得更模块化、更易维护——这是从&quot;会写触发器&quot;到&quot;会编程&quot;的关键一步。</p><h3 id="函数重载与多态" tabindex="-1">函数重载与多态 <a class="header-anchor" href="#函数重载与多态" aria-label="Permalink to “函数重载与多态”">​</a></h3><p><strong>函数重载</strong>是指在同一作用域内，定义多个同名函数，但它们的参数列表不同（参数类型或参数数量不同）。调用时，编译器会根据你传入的参数自动选择正确的函数版本[^1]。</p><blockquote><p><strong>💡 新手提示</strong>：想象一下&quot;加法&quot;这个概念——两个整数相加和两个小数相加看起来不同，但都可以叫&quot;加法&quot;。函数重载就是让计算机自动判断该用哪种&quot;加法&quot;。</p></blockquote><p>在vJASS中实现函数重载，需要借助<code>//! runtextmacro</code>语法配合静态方法：</p><ol><li><p><strong>第一步：创建库文件</strong> — 在WE中新建一个文本触发器（Trigger），命名为<code>MathUtils</code>[^4]</p></li><li><p><strong>第二步：定义静态方法</strong> — 输入以下代码框架：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>library MathUtils</span></span>
<span class="line"><span>    struct Math</span></span>
<span class="line"><span>        static method addInt takes integer a, integer b returns integer</span></span>
<span class="line"><span>            return a + b</span></span>
<span class="line"><span>        endmethod</span></span>
<span class="line"><span>        static method addReal takes real a, real b returns real</span></span>
<span class="line"><span>            return a + b</span></span>
<span class="line"><span>        endmethod</span></span>
<span class="line"><span>    endstruct</span></span>
<span class="line"><span>endlibrary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div></li><li><p><strong>第三步：调用重载函数</strong> — 在其他触发器中使用<code>Math.addInt(1, 2)</code>或<code>Math.addReal(1.5, 2.5)</code>来调用对应版本</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常犯的错误是在同一个scope内定义两个参数完全相同的同名函数。这会导致编译错误！重载的关键是<strong>参数列表必须不同</strong>。</p></blockquote><h3 id="接口与实现" tabindex="-1">接口与实现 <a class="header-anchor" href="#接口与实现" aria-label="Permalink to “接口与实现”">​</a></h3><p><strong>接口（Interface）</strong>是一种&quot;契约&quot;，它只定义方法的名字和参数，不包含具体实现代码。任何&quot;实现&quot;这个接口的结构体（struct）都必须提供这些方法的具体代码[^1][^2]。</p><blockquote><p><strong>💡 新手提示</strong>：接口就像一份&quot;工作要求清单&quot;——它规定了你需要会什么技能，但不规定你怎么去做。不同的员工可以用不同的方式完成同一项技能要求。</p></blockquote><ol><li><p><strong>第一步：声明接口</strong> — 使用<code>//! i</code>指令定义接口：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>//! i interface Damageable</span></span>
<span class="line"><span>    // 定义受伤方法</span></span>
<span class="line"><span>    method takeDamage takes integer amount returns nothing = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>第二步：创建实现结构体</strong> — 定义struct时使用<code>implement</code>关键字：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>struct Hero implements Damageable</span></span>
<span class="line"><span>    integer hp = 1000</span></span>
<span class="line"><span>    method takeDamage takes integer amount returns nothing</span></span>
<span class="line"><span>        set hp = hp - amount</span></span>
<span class="line"><span>    endmethod</span></span>
<span class="line"><span>endstruct</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li><li><p><strong>第三步：传递接口参数</strong> — 现在你的函数可以接受任何实现了<code>Damageable</code>接口的类型：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function Attack takes Damageable target returns nothing</span></span>
<span class="line"><span>    call target.takeDamage(50)</span></span>
<span class="line"><span>endfunction</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li></ol><h3 id="作用域与命名空间" tabindex="-1">作用域与命名空间 <a class="header-anchor" href="#作用域与命名空间" aria-label="Permalink to “作用域与命名空间”">​</a></h3><p><strong>作用域（Scope）</strong>和<strong>命名空间</strong>帮助你组织代码，防止变量名冲突。在大型地图中，可能有几十个触发器同时运行，如果大家都用<code>i</code>、<code>temp</code>这样的通用变量名，后果不堪设想[^3]。</p><ol><li><p><strong>第一步：创建独立作用域</strong> — 使用<code>scope</code>关键字包裹一段代码：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>scope PlayerManager</span></span>
<span class="line"><span>    private integer currentPlayer = 0</span></span>
<span class="line"><span>    function GetCurrentPlayer takes nothing returns integer</span></span>
<span class="line"><span>        return currentPlayer</span></span>
<span class="line"><span>    endfunction</span></span>
<span class="line"><span>endscope</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li><li><p><strong>第二步：控制访问权限</strong> — 注意上面代码中<code>currentPlayer</code>前加了<code>private</code>关键字，这意味着它只能在<code>PlayerManager</code>内部被访问。外部代码无法直接修改这个变量，只能通过<code>GetCurrentPlayer</code>函数读取。</p></li><li><p><strong>第三步：使用<code>requires</code>管理依赖顺序</strong> — 当一个库需要依赖另一个库时：</p><div class="language-vJ line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJ</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol><h2 id="自定义数据结构与类型" tabindex="-1">自定义数据结构与类型 <a class="header-anchor" href="#自定义数据结构与类型" aria-label="Permalink to “自定义数据结构与类型”">​</a></h2><p>本节我们将学习vJASS中的自定义数据结构，包括<strong>结构体(Struct)</strong>、<strong>哈希表(HashTable)</strong>、<strong>动态数组和链表</strong>。学完这节后，你将能够用代码组织复杂的数据，让技能系统和游戏逻辑更加清晰、高效。[^1][^2]</p><h3 id="struct结构体详解" tabindex="-1">Struct结构体详解 <a class="header-anchor" href="#struct结构体详解" aria-label="Permalink to “Struct结构体详解”">​</a></h3><p><strong>什么是Struct（结构体）？</strong> 简单来说，struct就像是一个自定义的&quot;数据包&quot;。你可以把多个相关的变量打包在一起管理。[^1]</p><p>为什么要用struct？想象你要做一个技能系统，每个技能都有：伤害值、冷却时间、施法范围。如果不用struct，你需要为每个技能单独创建多个变量，代码会变得混乱。而用struct，你只需创建10个&quot;技能实例&quot;，每个实例自带这些属性，代码清晰多了。[^5]</p><p><strong>第一步：定义Struct</strong> — 在脚本最上方（通常在globals...endglobals之后）使用关键字<code>struct</code>定义结构体：</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>struct SkillData</span></span>
<span class="line"><span>    integer damage</span></span>
<span class="line"><span>    real cooldown</span></span>
<span class="line"><span>    real range</span></span>
<span class="line"><span>endstruct</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>第二步：创建Struct实例</strong> — 在你需要的地方，通过<code>SkillData.create()</code>创建新的技能数据实例。[^1]</p><p><strong>第三步：访问成员变量</strong> — 使用点符号访问：<code>mySkill.damage = 100</code></p><blockquote><p><strong>💡 新手提示</strong>：struct的命名建议使用驼峰命名法（如SkillData），变量名要有意义，方便以后阅读代码。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：忘记调用<code>.create()</code>就使用struct会导致游戏崩溃。一定要确保在使用前初始化实例。</p></blockquote><h3 id="hashtable高级应用" tabindex="-1">HashTable高级应用 <a class="header-anchor" href="#hashtable高级应用" aria-label="Permalink to “HashTable高级应用”">​</a></h3><p><strong>什么是HashTable？</strong> 哈希表是一种&quot;键值对&quot;存储结构，你可以理解为带编号的超级仓库。每个数据都有一个&quot;钥匙&quot;（键key）和&quot;物品&quot;（值value）。[^6]</p><p><strong>为什么用HashTable？</strong> 当你需要临时存储大量关联数据时很有用。比如记录每个单位受到的伤害、每个玩家的金币数量等。</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>local hashtable h = InitHashtable()</span></span>
<span class="line"><span>call SaveInteger(h, unitHandle, 0, 100)  // 存储</span></span>
<span class="line"><span>call LoadInteger(h, unitHandle, 0)       // 读取</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>第一步：创建哈希表</strong> — 使用<code>InitHashtable()</code>创建新哈希表[^6]</p><p><strong>第二步：存储数据</strong> — <code>SaveInteger/SaveReal/SaveStr</code>分别存储整数/小数/文字</p><p><strong>第三步：读取数据</strong> — 对应使用<code>LoadInteger/LoadReal/LoadStr</code></p><blockquote><p><strong>💡 新手提示</strong>：使用完毕后记得用<code>DestroyHashtable(h)</code>销毁哈希表，节省内存。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：读取不存在的键会返回默认值（整数为0），新手常误以为没存进去数据。</p></blockquote><h3 id="动态数组与链表" tabindex="-1">动态数组与链表 <a class="header-anchor" href="#动态数组与链表" aria-label="Permalink to “动态数组与链表”">​</a></h3><p><strong>动态数组 vs 普通数组</strong> 普通数组需要固定大小，动态数组可以随时增减元素。vJASS中可以使用<strong>链表(List)</strong>实现类似功能。[^5]</p><p>链表适合管理&quot;数量不固定&quot;的元素列表，比如：</p><ul><li>地图上存活的敌人单位列表</li><li>玩家当前拥有的物品</li><li>技能连锁的目标</li></ul><p><strong>第一步：使用自定义链表库</strong> — 在脚本开头引入链表相关库代码</p><p><strong>第二步：创建链表</strong> — <code>thistype.create()</code> 创建新列表</p><p><strong>第三步：添加/删除元素</strong> — 使用<code>.push()</code>添加、<code>.remove()</code>删除</p><blockquote><p><strong>💡 新手提示</strong>：如果列表元素数量固定且较小，用普通数组反而更快。只有数量经常变化时才用链表。</p></blockquote><blockquote><p>**�</p></blockquote><h2 id="代码模块化与库系统" tabindex="-1">代码模块化与库系统 <a class="header-anchor" href="#代码模块化与库系统" aria-label="Permalink to “代码模块化与库系统”">​</a></h2><p>本节你将学习如何使用 vJASS 的 <code>library</code> 语句来组织代码，以及如何通过模块（module）实现代码复用。这些是vJASS区别于普通JASS的核心功能，能让你像搭积木一样构建复杂的游戏逻辑[^1][^2]。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>创建你的第一个library</strong> — 在触发器编辑器中新建一个“自定义代码”触发器（不是普通触发器），然后输入：</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>library MyFirstLibrary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>记得在末尾加上 <code>endlibrary</code>，这就像给代码包上一层包装袋。</p></li><li><p><strong>理解library的独立性</strong> — library 中的代码在地图加载时就会自动执行，不需要手动调用。这和普通触发器不同，普通触发器需要事件触发才会运行[^3]。</p></li><li><p><strong>使用requires关键字管理依赖</strong> — 如果你的library需要用到另一个library的代码，使用 <code>requires</code> 来声明依赖关系：</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>library SpellSystem requires UnitHelper</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样当SpellSystem加载时，UnitHelper会自动先被加载，确保你用到的功能已经准备就绪[^1]。</p></li><li><p><strong>使用initializer设置初始化函数</strong> — 如果library需要在加载时执行初始化代码（设置默认值、预加载资源等），添加 <code>initializer</code>：</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>library MyLibrary initializer onInit</span></span>
<span class="line"><span>    function onInit()</span></span>
<span class="line"><span>        // 这里写初始化代码</span></span>
<span class="line"><span>    endfunction</span></span>
<span class="line"><span>endlibrary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记在library末尾添加 <code>endlibrary</code>，导致地图报错“语法错误”。另一个常见问题是循环依赖——A requires B，B requires A，这样地图永远加载不了。解决方法是重新设计代码结构，避免相互依赖。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>学完本节后，你应该能够使用 <code>library...endlibrary</code> 结构组织代码，通过 <code>requires</code> 管理库之间的依赖关系，并理解 <code>initializer</code> 的作用。掌握这些基础后，你的地图代码将更容易维护和分享给其他开发者[^5]。</p><h2 id="性能优化与最佳实践" tabindex="-1">性能优化与最佳实践 <a class="header-anchor" href="#性能优化与最佳实践" aria-label="Permalink to “性能优化与最佳实践”">​</a></h2><p>本节将学习如何让你的vJASS代码运行得更快、更稳定。你会掌握提升代码效率的核心技巧，以及避免内存泄漏的正确方法。掌握这些知识后，你的地图在大规模战斗或复杂逻辑下也不会卡顿。</p><h3 id="代码执行效率提升" tabindex="-1">代码执行效率提升 <a class="header-anchor" href="#代码执行效率提升" aria-label="Permalink to “代码执行效率提升”">​</a></h3><p>编写触发器代码时，效率决定了玩家体验。执行一次不必要的操作可能微不足道，但如果每秒执行几千次，就会严重拖慢游戏。</p><h4 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><p><strong>优先使用局部变量而非全局变量</strong>[^1] — 在函数开头用 <code>local</code> 声明变量，例如 <code>local unit u = GetTriggerUnit()</code>。局部变量访问速度更快，而且不会和其他代码产生冲突。</p></li><li><p><strong>减少重复获取游戏数据</strong>[^2] — 不要在循环内部反复调用 <code>GetUnitsInRectAll()</code> 这类函数。先获取一次，存入变量，循环中使用这个变量。</p></li><li><p><strong>避免频繁创建和销毁单位组（Unit Group）</strong> — 单位组是临时容器，每次创建都要消耗资源。在需要重复使用时，先用 <code>GroupClear()</code> 清空后复用，而不是 <code>DestroyGroup()</code> 再 <code>CreateGroup()</code>。</p></li><li><p><strong>把不变的计算提前做</strong>[^3] — 如果某个数值在整个函数中不变，不要放在循环里计算，在循环之前算一次存起来。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：打开触发器编辑器时，按 <code>Ctrl + U</code> 可以查看当前触发器执行的日志，帮助你发现哪里执行次数异常多。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手喜欢在&quot;每个计时器周期&quot;里大量创建单位组或单位，以为&quot;反正用完就没了&quot;。实际上魔兽的内存管理有限，频繁创建销毁会导致游戏变卡甚至崩溃。记住：<strong>复用比销毁重建更好</strong>。</p></blockquote><h3 id="内存管理与资源控制" tabindex="-1">内存管理与资源控制 <a class="header-anchor" href="#内存管理与资源控制" aria-label="Permalink to “内存管理与资源控制”">​</a></h3><p>内存就像你的背包，空间有限。每次你在代码中&quot;创建&quot;一个东西（比如计时器、单位组），就占用了一个格子。如果创建后忘记&quot;丢掉&quot;（销毁），这个格子就永远被占着，这就是&quot;内存泄漏&quot;。</p><h4 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><p><strong>养成&quot;创建必销毁&quot;的习惯</strong>[^2] — 每当你使用 <code>CreateTimer()</code> 创建计时器，用完后必须调用 <code>DestroyTimer(t)</code>。每当你用 <code>CreateGroup()</code> 创建单位组，用完后必须 <code>DestroyGroup(g)</code>。</p></li><li><p><strong>使用 <code>onDestroy</code> 库自动清理</strong>[^1] — vJASS支持面向对象编程，你可以用 <code>private struct</code> 定义一个结构体，在其中编写 <code>method onDestroy()</code> 自动执行清理代码。这样无论何时销毁对象，资源都会被正确释放。</p></li><li><p><strong>谨慎使用触发器</strong> — 每个触发器都会占用内存。功能相似的触发器可以合并，减少总数。删除不需要的触发器时，先 <code>Disable</code> 确认地图运行正常，再真正删除。</p></li><li><p><strong>注意数组大小</strong>[^5] — 在WE中创建数组变量时，分配的索引数量直接影响内存占用。只设置你需要的大小（默认16000足够），不要贪多。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：调试时打开WE的&quot;计时器窗口&quot;（Trigger → Timer Window），可以实时看到当前活跃的计时器和触发器数量，帮助你发现是否有泄漏。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：以为&quot;单位死亡后单位组就自动清空&quot;。实际上单位组里的单位只是引用，死亡后你需要手动 <code>GroupRemoveUnit()</code> 移除，否则这个单位占用的&quot;格子&quot;不会被释放。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>学完本节，你应该能够：</p><ul><li>识别代码中哪些地方可能造成性能瓶颈</li><li>正确使用局部变量和单位组复用技巧</li><li>为每个创建的计时器和单位组编写对应的销毁代码</li><li>使用面向对象的 <code>onDestroy</code> 机制自动化资源清理</li></ul><p><strong>立即行动</strong>：打开你之前写的一个vJASS脚本，数一数里面有多少个 <code>CreateTimer()</code> 或 <code>CreateGroup()</code>，检查是否每一个都有对应的 <code>Destroy</code> 语句。如果有遗漏，这就是你第一个优化目标！</p><h2 id="常见设计模式应用" tabindex="-1">常见设计模式应用 <a class="header-anchor" href="#常见设计模式应用" aria-label="Permalink to “常见设计模式应用”">​</a></h2><p>本节将学习两个最重要的设计模式：<strong>单例模式</strong>和<strong>事件系统</strong>。学完本节后，你将能够写出更专业、更易维护的vJASS代码——就像真正的游戏开发者一样！</p><hr><h3 id="单例模式实现" tabindex="-1">单例模式实现 <a class="header-anchor" href="#单例模式实现" aria-label="Permalink to “单例模式实现”">​</a></h3><p><strong>什么是单例模式？</strong> 想象你需要一个&quot;游戏管家&quot;——整个地图只需要一个，不能有第二个。单例模式就是确保某个类只有<strong>唯一一份实例</strong>的设计方法[^1]。</p><h4 id="操作步骤-3" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-3" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><p><strong>定义私有静态变量</strong> — 创建一个<code>private static thistype instance</code>变量，用来存储唯一的实例[^2]</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>private static thistype instance = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>创建私有构造函数</strong> — 把<code>construct</code>方法设为<code>private</code>，防止外部随意创建对象</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>private construct() endconstruct</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>创建公开获取方法</strong> — 写一个<code>static method create takes nothing returns thistype</code>，检查实例是否已存在</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>static method create takes nothing returns thistype</span></span>
<span class="line"><span>    if instance == 0 then</span></span>
<span class="line"><span>        set instance = thistype.allocate()</span></span>
<span class="line"><span>    endif</span></span>
<span class="line"><span>    return instance</span></span>
<span class="line"><span>endmethod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li></ol><blockquote><p><strong>💡 新手提示</strong>：所有需要&quot;全局唯一&quot;的系统都适合用单例，比如游戏管理器、音效控制器、存档系统等。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记检查实例是否已存在，导致每次调用<code>create</code>都创建新对象，浪费内存。</p></blockquote><hr><h3 id="事件系统构建" tabindex="-1">事件系统构建 <a class="header-anchor" href="#事件系统构建" aria-label="Permalink to “事件系统构建”">​</a></h3><p><strong>什么是事件系统？</strong> 简单说，就是&quot;当某件事发生时，自动执行对应代码&quot;的机制。比如&quot;单位死亡时扣金币&quot;、&quot;英雄升级时播放音效&quot;等[^3]。</p><h4 id="操作步骤-4" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-4" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><p><strong>创建事件表</strong> — 用<code>hashtable</code>（哈希表）存储&quot;谁监听什么事件&quot;</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>private hashtable ht = InitHashtable()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>编写注册函数</strong> — 让其他代码可以&quot;订阅&quot;某个事件</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>static method registerEvent takes unit u, integer eventType, code callback returns nothing</span></span>
<span class="line"><span>    // 把回调函数存入哈希表</span></span>
<span class="line"><span>endmethod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>编写触发函数</strong> — 当事件发生时，自动执行所有已注册的回调</p><div class="language-vjass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vjass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>static method triggerEvent takes integer eventType returns nothing</span></span>
<span class="line"><span>    // 从哈希表取出并执行所有回调</span></span>
<span class="line"><span>endmethod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>在触发器中调用</strong> — 在WE的触发器编辑器中，当事件发生时调用你写的事件系统</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：也可以直接使用WE自带的Trigger系统来实现简单事件，没必要什么都自己写。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手混淆&quot;注册事件&quot;和&quot;触发事件&quot;——注册是&quot;告诉系统我想监听&quot;，触发是&quot;系统通知你有事发生了&quot;。</p></blockquote><hr><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上两个模式的学习后，你已经掌握了：</p><ul><li>✅ 如何确保某个系统只有一份实例（单例模式）</li><li>✅ 如何构建&quot;事件触发-响应&quot;的代码结构</li></ul><p>这两个模式是vJASS开发中最常用的技巧，建议在编写复杂地图时多多运用。</p><h2 id="调试技巧与错误排查" tabindex="-1">调试技巧与错误排查 <a class="header-anchor" href="#调试技巧与错误排查" aria-label="Permalink to “调试技巧与错误排查”">​</a></h2><p>在本节中，你将学习如何识别和解决 vJASS 代码中最常见的错误，以及如何使用日志输出来测试你的代码。学完本节后，你将能够独立排查大多数简单的代码问题，不用再因为一串红色报错信息而抓狂。</p><h3 id="常见编译错误解析" tabindex="-1">常见编译错误解析 <a class="header-anchor" href="#常见编译错误解析" aria-label="Permalink to “常见编译错误解析”">​</a></h3><p>当你点击&quot;保存&quot;或&quot;测试地图&quot;时，如果代码有问题，World Editor 会在底部弹出一串红色文字——这就是<strong>编译错误提示</strong>。别慌，我们来一步步看懂它。</p><p><strong>第一步：找到错误信息的位置</strong>[^3]</p><p>打开 World Editor 后，编译错误通常会显示在编辑器底部的&quot;触发器编辑器&quot;面板中。错误信息一般长这样：<code>Error: Expected a name</code> 或 <code>Syntax error</code>。先找到这行字，它会告诉你问题出在哪里。</p><p><strong>第二步：看行号，找位置</strong>[^4]</p><p>错误信息后面通常跟着一个数字，比如 <code>line 5</code> 或 <code>at line 12</code>。这个数字就是出错的代码行号。在你的 vJASS 代码里，找到对应的那一行，这里通常就是问题根源。</p><p><strong>第三步：识别最常见的错误类型</strong>[^2]</p><p>新手最容易犯的三种错误：</p><ol><li><strong>缺少分号 <code>;</code></strong> — vJASS 每行代码必须以分号结尾，忘记写会导致整段代码报错</li><li><strong>括号不匹配</strong> — 左括号 <code>(</code> 或 <code>{</code> 必须有对应的右括号 <code>)</code> 或 <code>}</code></li><li><strong>变量名拼写错误</strong> — 比如你定义了 <code>local unit u</code>，但使用时写成了 <code>unt u</code>，系统会不认识</li></ol><p><strong>第四步：善用排除法缩小范围</strong></p><p>如果错误提示的位置不够明确，试着把一段代码<strong>注释掉</strong>（在开头加 <code>//</code>），然后逐段取消注释，直到找到真正出错的那一行。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手看到满屏红色报错就慌了，直接把整个代码删掉重写。其实90%的情况下，错误只有一个根源，把那一行修好，其他连锁错误就会自动消失。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：养成每写完3-5行就按 Ctrl+S 保存的习惯。频繁保存可以让你在出错时快速定位是哪一步出了问题。</p></blockquote><h3 id="日志输出与测试" tabindex="-1">日志输出与测试 <a class="header-anchor" href="#日志输出与测试" aria-label="Permalink to “日志输出与测试”">​</a></h3><p>有时候代码没有语法错误，但运行起来效果不对。这时候你需要<strong>打印日志</strong>——也就是让游戏&quot;告诉你&quot;某个变量的值是什么。</p><p><strong>第一步：了解 BJ 函数中的调试工具</strong>[^4]</p><p>Warcraft III 提供了一些内置的调试函数，比如 <code>DisplayTextToForce</code>，它可以在屏幕上显示一行文字：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call DisplayTextToForce(bj_FORCE_ALL_PLAYERS, &quot;调试信息：我在这里！&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>把这行代码放在你想检查的地方，运行地图时屏幕上就会弹出文字。</p><p><strong>第二步：在关键位置插入测试代码</strong></p><p>比如你写了一个计算伤害的函数，不确定它有没有被调用，就在函数开头加一行 <code>DisplayTextToForce</code>。如果游戏运行时看到了这行文字，说明函数确实执行了。</p><p><strong>第三步：用整数或字符串输出变量值</strong></p><p>单纯打印&quot;我在这里&quot;只能确认代码执行了，但如果想知道某个变量的具体数值，可以这样做：</p><div class="language-vJASS line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vJASS</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call DisplayTextToForce(bj_FORCE_ALL_PLAYERS, &quot;当前生命值是：&quot; + I2S(GetUnitLife(u)))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>I2S</code> 是把整数转换成文字的函数，<code>R2S</code> 可以转换小数。这样你就能看到单位的实际生命值。</p><p><strong>第四步：测试完成后记得删除调试代码</strong></p><p>调试用的打印语句只是临时工具，完成测试后一定要删掉，否则正式游戏时满屏都是乱七八糟的文字，影响玩家体验。</p><blockquote><p><strong>💡 新手提示</strong>：如果调试信息太多看不清，可以把 <code>bj_FORCE_ALL_PLAYERS</code> 改成只显示给某个特定玩家，比如 <code>Player(0)</code>（也就是玩家1）。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>读懂 World Editor 底部弹出的编译错误提示，找到出错的具体行号</li><li>识别并修复最常见的几种语法错误（分号、括号、拼写）</li><li>使用 <code>DisplayTextToForce</code> 在游戏中输出调试信息，检查变量值</li><li>有条理地进行&quot;排除法&quot;排查，快速定位问题根源</li></ul><p>调试是编程的必经之路，没有人的代码第一次就能完美运行。多练习、多观察错误信息，你会越来越熟练！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/vjass-oop-lesson.128236/" target="_blank" rel="noreferrer">vJASS OOP Lesson | HIVE</a> — accessed 2026-05-08 [^2]: <a href="https://www.bilibili.com/video/BV1e3xpzeEgZ/" target="_blank" rel="noreferrer">魔兽地图编辑器vjass环境 / vJassGo插件 / 最完整的VJASS中文教程</a> — accessed 2026-05-08 [^3]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=127853" target="_blank" rel="noreferrer">vJASS Features Tutorial</a> — accessed 2026-05-08 [^4]: <a href="https://vjass.wordpress.com/" target="_blank" rel="noreferrer">VJASS info</a> — accessed 2026-05-08 [^5]: <a href="https://github.com/zxcvbffg/Warcraft3-vJASS-" target="_blank" rel="noreferrer">GitHub - Warcraft3-vJASS</a> — accessed 2026-05-08 [^6]: <a href="https://github.com/topics/vjass" target="_blank" rel="noreferrer">vjass · GitHub Topics</a> — accessed 2026-05-08</p>`,127)])])}const u=e(t,[["render",r]]);export{b as __pageData,u as default};
